const items=$input.all();
const out=[];
for (let i=0;i<items.length;i++){
  const it=items[i]; const bin=it.binary||{}; const j=it.json;
  const docs=[];
  for (const key of Object.keys(bin)){
    const b=bin[key]; const mt=(b.mimeType||'').toLowerCase(); const nm=(b.fileName||'').toLowerCase();
    if(mt.includes('pdf')||nm.endsWith('.pdf')){
      const buf=await this.helpers.getBinaryDataBuffer(i,key);
      docs.push({type:'document',source:{type:'base64',media_type:'application/pdf',data:buf.toString('base64')}});
    }
  }
  if(docs.length===0){throw new Error('У листі немає PDF-вкладень.');}
  const textBody=(j.textPlain||j.text||j.textHtml||'').toString();
  let truck='',trailer='';
  const m=textBody.match(/([\p{L}\p{N}\-]{3,})\s*\/\s*([\p{L}\p{N}\-]{3,})/u);
  if(m){truck=m[1].trim();trailer=m[2].trim();}
  function hdr(name){if(Array.isArray(j.headers)){const h=j.headers.find(x=>(x.name||'').toLowerCase()===name);if(h)return h.value;}return j[name]||j[name.charAt(0).toUpperCase()+name.slice(1)]||'';}
  const prompt="Ти обробляєш комерційні документи на морський вантаж. У вкладеннях можуть бути різні документи.\nВИКОРИСТОВУЙ ДАНІ ВИКЛЮЧНО з двох документів: Bill of Lading (коносамент) та Commercial Invoice (інвойс). Решту ІГНОРУЙ.\nПоверни СТРОГО валідний JSON без пояснень і markdown, з полями:\n{\"container\":\"номер контейнера з Bill of Lading\",\"sender\":\"назва і повна адреса відправника (Shipper/Seller)\",\"receiver\":\"назва і повна адреса отримувача (Consignee)\",\"port\":\"порт прибуття (Port of Discharge)\",\"weight\":\"вага БРУТТО (Gross Weight) з одиницею\",\"invoice\":\"номер інвойсу (Invoice No.)\"}\nВага — ОБОВ`ЯЗКОВО брутто. Якщо поля немає — постав \"\".";
  const body={model:'claude-sonnet-4-6',max_tokens:1024,messages:[{role:'user',content:docs.concat([{type:'text',text:prompt}])}]};
  out.push({json:{body,truck,trailer,from:(j.from&&j.from.value&&j.from.value[0]&&j.from.value[0].address)||hdr('from')||j.from||'',cc:(j.cc&&j.cc.text)||hdr('cc')||'',subject:j.subject||'',messageId:j.messageId||hdr('message-id')||''}});
}
return out;

const resp=$input.item.json;
let text=(resp.content&&Array.isArray(resp.content))?resp.content.map(c=>c.text||'').join(''):(resp.text||'').toString();
text=text.replace(/```json/gi,'').replace(/```/g,'').trim();
let data={};try{data=JSON.parse(text);}catch(e){const mm=text.match(/\{[\s\S]*\}/);if(mm)data=JSON.parse(mm[0]);}
const prep=$('Підготовка даних').item.json;
const container=(data.container||'').toString().trim();
const sender=(data.sender||'').toString().trim();
const receiver=(data.receiver||'').toString().trim();
const port=(data.port||'').toString().trim();
const weight=(data.weight||'').toString().trim();
const invoice=(data.invoice||'').toString().trim();
const truck=prep.truck||'';const trailer=prep.trailer||'';
const receiverShort=receiver.split(/[,\n]/)[0].trim();
const docTitle='CMR draft №'+container+' '+receiverShort;
  const ph=[['{{'+'sender}}',sender],['{{'+'receiver}}',receiver],['{{'+'port}}',port],['{{'+'invoice}}',invoice],['{{'+'container}}',container],['{{'+'weight}}',weight],['{{'+'truck}}',truck],['{{'+'trailer}}',trailer]];
  const docsBody={requests:ph.map(p=>({replaceAllText:{containsText:{text:p[0],matchCase:true},replaceText:String(p[1]||'')}}))};
return [{json:{container,sender,receiver,port,weight,invoice,truck,trailer,docTitle,docsBody,from:prep.from,cc:prep.cc,subject:prep.subject}}];
